for (const item of $input.all()) {

  let rawText = item.json.output || item.json.text || item.json.customer_message || "";

  try {
    let cleanText = rawText.replace(/```json/gi, "").replace(/```/gi, "").trim();
    let aiData = JSON.parse(cleanText);

    // 1. Map the core AI fields
    item.json.customer_message = aiData.customer_message;

    // 🏠 NEW: Clean the address to ONLY keep House and Block (Removes Wapda City)
    let rawAddress = aiData.customer_address || "";
    item.json.customer_address = rawAddress
      .replace(/(wapda\s*city|wapda|faisalabad)/gi, '') // Strip out city names
      .split(',')                                       // Split by commas
      .map(part => part.trim())                         // Remove extra spaces
      .filter(part => part !== '')                      // Remove empty parts
      .join(', ');                                      // Join back together cleanly

    item.json.customer_order = aiData.customer_order || "";
    item.json.payment_method = aiData.payment_method || "";

    // 2. The Metadata Override (Prioritize WhatsApp profile name/number)
    item.json.customer_name = (item.json.customer_name && item.json.customer_name.trim() !== "") ? item.json.customer_name : aiData.customer_name;
    item.json.customer_number = (item.json.customer_number && item.json.customer_number.trim() !== "") ? item.json.customer_number : aiData.customer_number;

    // 3. Ensure price is a number (Fallback to 0 if AI missed it)
    item.json.total_price = aiData.total_price ? Number(aiData.total_price) : 0;
    item.json.total = item.json.total_price; // Safe mapping for your HTTP Request node

    // 4. Auto-generate today's exact date (YYYY-MM-DD)
    const today = new Date();
    item.json.order_date = today.toISOString().split('T')[0];

  } catch (error) {
    item.json.customer_message = "Sorry, I'm still learning! Could you repeat that?";
    item.json.customer_address = "";
    item.json.customer_order = "";
    item.json.total_price = 0;
    item.json.total = 0;
    item.json.order_date = new Date().toISOString().split('T')[0];
  }

  // 5. The Gatekeeper: Check if the 4 core fields are filled
  if (item.json.customer_name !== "" && 
      item.json.customer_address !== "" && 
      item.json.customer_order !== "" && 
      item.json.payment_method !== "") {

    item.json.should_proceed = true;
    item.json.missing_fields = "none";
  } else {
    item.json.should_proceed = false;
  }
}

return $input.all();

for (const item of $input.all()) {
  let rawText = item.json.output || item.json.text || item.json.customer_message || "";
  try {
    let cleanText = rawText.replace(/```json/gi, "").replace(/```/gi, "").trim();
    let aiData = JSON.parse(cleanText);

    item.json.customer_message = aiData.customer_message;

    // 🏠 NEW: Clean the address to ONLY keep House and Block (Removes Wapda City)
    let rawAddress = aiData.customer_address || "";
    item.json.customer_address = rawAddress
      .replace(/(wapda\s*city|wapda|faisalabad)/gi, '') // Strip out city names
      .split(',')                                       // Split by commas
      .map(part => part.trim())                         // Remove extra spaces
      .filter(part => part !== '')                      // Remove empty parts
      .join(', ');                                      // Join back together cleanly

    item.json.customer_order = aiData.customer_order || "";

    // Standardize Payment Method
    let payment = aiData.payment_method || "";
    let paymentLower = payment.toLowerCase();

    if (paymentLower.includes("jazz")) {
      item.json.payment_method = "JazzCash";
    } else if (payment.toUpperCase() === "COD" || paymentLower.includes("cash") || paymentLower.includes("delivery")) {
      item.json.payment_method = "Cash on Delivery";
    } else {
      item.json.payment_method = payment;
    }

    item.json.customer_name = (item.json.customer_name && item.json.customer_name.trim() !== "") ? item.json.customer_name : aiData.customer_name;

    let rawNumber = (item.json.customer_number && item.json.customer_number.trim() !== "") ? item.json.customer_number : aiData.customer_number;
    item.json.customer_number = rawNumber ? rawNumber.replace(/[^0-9]/g, '') : "";

    // 🔥 THE FIX: Change "total_price" to "total" so your backend recognizes it!
    item.json.total = aiData.total_price ? Number(aiData.total_price) : 0;

    item.json.order_date = new Date().toISOString().split('T')[0];
  } catch (error) {
    item.json.customer_message = "Sorry, I'm still learning! Could you repeat that?";
    item.json.customer_address = "";
    item.json.customer_order = "";
    item.json.payment_method = "";
    item.json.total = 0;
  }

  // 🛡️ The Simplified Gatekeeper: Instant Pass
  let isComplete = false;

  if (item.json.customer_name !== "" && 
      item.json.customer_address !== "" && 
      item.json.customer_order !== "" && 
      item.json.payment_method !== "") {

    // All info is gathered. Instantly mark as true so it goes to the DB.
    isComplete = true; 

    // Hard-override the final message to guarantee perfection
    if (item.json.payment_method === "JazzCash") {
      item.json.customer_message = "Order confirmed! Your total is Rs. " + item.json.total + ". Please pay to JazzCash: 0300-7918682 and show the payment screenshot to our rider when they arrive in about 30 minutes! 🛵";
    } else if (item.json.payment_method === "Cash on Delivery") {
      item.json.customer_message = "Order confirmed! Your total is Rs. " + item.json.total + ". Please have the cash ready for our rider, arriving in about 30 minutes! 🍔";
    }
  }

  item.json.should_proceed = isComplete;
}
return $input.all();
